/* App min js */
(function () {
    // Sidebar toggle
    const buttonToggleMenu = document.querySelector('.button-toggle-menu');
    if (buttonToggleMenu) {
        buttonToggleMenu.addEventListener('click', function () {
            document.body.classList.toggle('sidebar-collapsed');
        });
    }

    // Small sidebar hover toggle
    const buttonSmHover = document.querySelector('.button-sm-hover');
    if (buttonSmHover) {
        buttonSmHover.addEventListener('click', function () {
            document.body.classList.remove('sidebar-collapsed');
        });
    }

    // Initialize SimpleBar
    const scrollbar = document.querySelector('[data-simplebar]');
    if (scrollbar && typeof SimpleBar !== 'undefined') {
        new SimpleBar(scrollbar);
    }
})();